# Medal counts for the top 5 countries at the 2022 Commonwealth Games
top_countries = {
    'Australia': {'gold': 67, 'total': 179},
    'England': {'gold': 58, 'total': 176},
    'Canada': {'gold': 26, 'total': 92},
    'India': {'gold': 22, 'total': 61},
    'New Zealand': {'gold': 20, 'total': 49}
}

# Calculate total medals for each country
total_medals = {country: data['total'] for country, data in top_countries.items()}
print(total_medals)
